/// Fast exp() for audio circuit simulation.
/// Input clamped to [-40, 40] (matches melange safe_exp convention).
///
/// Default: polynomial approximation (<0.0004% error, ~6x faster than libm).
/// To use hardware/libm exp, compile with: `--cfg melange_precise_exp`
#[inline(always)]
fn fast_exp(x: f64) -> f64 {
    #[cfg(melange_precise_exp)]
    {
        x.clamp(-40.0, 40.0).exp()
    }
    #[cfg(not(melange_precise_exp))]
    {
        // Range reduction + 5th-order minimax polynomial. <0.0004% max relative error.
        // No lookup tables, no libm dependency, branchless hot path.
        let x = x.clamp(-40.0, 40.0);
        const LN2_INV: f64 = std::f64::consts::LOG2_E;
        const LN2_HI: f64 = 0.6931471803691238;
        const LN2_LO: f64 = 1.9082149292705877e-10;
        const SHIFT: f64 = 6755399441055744.0; // 2^52 + 2^51
        let z = x * LN2_INV + SHIFT;
        let n_i64 = z.to_bits() as i64 - SHIFT.to_bits() as i64;
        let n = n_i64 as f64;
        let f = (x - n * LN2_HI) - n * LN2_LO;
        let p = 1.0
            + f * (1.0
                + f * (0.5
                    + f * (0.16666666666666607
                        + f * (0.04166666666665876 + f * 0.008333333333492337))));
        let pow2n = f64::from_bits(((1023 + n_i64) as u64) << 52);
        p * pow2n
    }
}

/// Fast ln() for audio circuit simulation.
/// Symmetric log series (~0.005% max relative error, ~3x faster than libm).
/// Only valid for positive inputs.
#[inline(always)]
fn fast_ln(x: f64) -> f64 {
    #[cfg(melange_precise_exp)]
    {
        x.ln()
    }
    #[cfg(not(melange_precise_exp))]
    {
        // Extract exponent and mantissa from IEEE 754 double
        let bits = x.to_bits();
        let e = ((bits >> 52) & 0x7FF) as i64 - 1023;
        // Normalize mantissa to [1, 2)
        let m_bits = (bits & 0x000F_FFFF_FFFF_FFFF) | 0x3FF0_0000_0000_0000;
        let m = f64::from_bits(m_bits);
        // Symmetric log series: u = (m-1)/(m+1), ln(m) = 2u(1 + u²/3 + u⁴/5 + u⁶/7)
        // For m in [1,2), u in [0,1/3): converges much faster than Taylor.
        let u = (m - 1.0) / (m + 1.0);
        let u2 = u * u;
        let ln_m =
            2.0 * u * (1.0 + u2 * (0.3333333333333333 + u2 * (0.2 + u2 * 0.14285714285714285)));
        ln_m + (e as f64) * std::f64::consts::LN_2
    }
}

// Canonical source: melange-primitives/src/nr.rs (pnjlim, fetlim)
// Duplicated here because generated code must be self-contained.

/// SPICE PN junction voltage limiting (from SPICE3f5 DEVpnjlim).
///
/// Limits large forward voltage steps on exponential I-V curves using
/// logarithmic compression. Only activates when vnew > vcrit with large step.
#[inline(always)]
fn pnjlim(vnew: f64, vold: f64, vt: f64, vcrit: f64) -> f64 {
    if vnew > vcrit && (vnew - vold).abs() > vt + vt {
        if vold >= 0.0 {
            let arg = 1.0 + (vnew - vold) / vt;
            if arg > 0.0 {
                vold + vt * arg.ln()
            } else {
                vcrit
            }
        } else {
            vt * (vnew / vt).ln()
        }
    } else {
        vnew
    }
}

/// SPICE FET voltage limiting (from SPICE3f5 DEVfetlim).
///
/// Prevents gate-source voltage from jumping across threshold boundary.
/// The allowed step size adapts to the distance from threshold.
#[inline(always)]
fn fetlim(vnew: f64, vold: f64, vto: f64) -> f64 {
    let delv = vnew - vold;
    let vtox = vto + 3.5;
    let vtsthi = (2.0 * (vold - vto)).abs() + 2.0;
    let vtstlo = vtsthi / 2.0 + 2.0;

    if vold >= vto {
        // Device is "on"
        if vold >= vtox {
            if delv <= 0.0 {
                // Going off
                if vnew >= vtox {
                    if -delv > vtstlo {
                        return vold - vtstlo;
                    }
                } else {
                    return vnew.max(vto + 2.0);
                }
            } else {
                // Staying on
                if delv >= vtsthi {
                    return vold + vtsthi;
                }
            }
        } else {
            // Middle region
            if delv <= 0.0 {
                return vnew.max(vto - 0.5);
            } else {
                return vnew.min(vto + 4.0);
            }
        }
    } else {
        // Device is "off"
        if delv <= 0.0 {
            if -delv > vtstlo {
                return vold - vtstlo;
            }
        } else if vnew <= vto + 0.5 {
            if delv > vtstlo {
                return vold + vtstlo;
            }
        } else {
            return vto + 0.5;
        }
    }
    vnew
}

// Canonical source: melange-devices/src/diode.rs (DiodeShockley)
// Duplicated here because generated code must be self-contained.

/// Diode current: i_d = is * (exp(v_d / n_vt) - 1)
#[inline(always)]
fn diode_current(v_d: f64, is: f64, n_vt: f64) -> f64 {
    let v_clamped = v_d.clamp(-40.0 * n_vt, 40.0 * n_vt);
    is * (fast_exp(v_clamped / n_vt) - 1.0)
}

/// Diode conductance: g_d = di/dv = (is / n_vt) * exp(v_d / n_vt)
#[inline(always)]
fn diode_conductance(v_d: f64, is: f64, n_vt: f64) -> f64 {
    let v_clamped = v_d.clamp(-40.0 * n_vt, 40.0 * n_vt);
    (is / n_vt) * fast_exp(v_clamped / n_vt)
}

/// Diode with series resistance: solve V_j + I(V_j)*RS = V_d for V_j,
/// then return I(V_j). Uses NR with step limiting.
#[inline(always)]
fn diode_current_with_rs(v_d: f64, is: f64, n_vt: f64, rs: f64) -> f64 {
    let max_step = 4.0 * n_vt;
    let mut v_j = if v_d > 0.0 { v_d.min(0.7) } else { v_d };
    for _ in 0..8 {
        let id = diode_current(v_j, is, n_vt);
        let gd = diode_conductance(v_j, is, n_vt);
        let f = v_j + id * rs - v_d;
        let fp = 1.0 + gd * rs;
        let mut delta = f / fp;
        delta = delta.clamp(-max_step, max_step);
        v_j -= delta;
        if delta.abs() < 1e-10 {
            break;
        }
    }
    diode_current(v_j, is, n_vt)
}

/// Diode conductance with series resistance: g_total = g_j / (1 + g_j * rs)
/// where g_j is evaluated at the NR-solved junction voltage.
#[inline(always)]
fn diode_conductance_with_rs(v_d: f64, is: f64, n_vt: f64, rs: f64) -> f64 {
    let max_step = 4.0 * n_vt;
    let mut v_j = if v_d > 0.0 { v_d.min(0.7) } else { v_d };
    for _ in 0..8 {
        let id = diode_current(v_j, is, n_vt);
        let gd = diode_conductance(v_j, is, n_vt);
        let f = v_j + id * rs - v_d;
        let fp = 1.0 + gd * rs;
        let mut delta = f / fp;
        delta = delta.clamp(-max_step, max_step);
        v_j -= delta;
        if delta.abs() < 1e-10 {
            break;
        }
    }
    let g_j = diode_conductance(v_j, is, n_vt);
    g_j / (1.0 + g_j * rs)
}

/// Reverse breakdown current: I_bv = -IBV * exp(-(v_d + BV) / n_vt)
/// Added to diode current when v_d < -BV.
#[inline(always)]
fn diode_breakdown_current(v_d: f64, n_vt: f64, bv: f64, ibv: f64) -> f64 {
    let x = (-(v_d + bv) / n_vt).clamp(-40.0, 40.0);
    -ibv * fast_exp(x)
}

/// Reverse breakdown conductance: dI_bv/dv = IBV/n_vt * exp(-(v_d + BV) / n_vt)
#[inline(always)]
fn diode_breakdown_conductance(v_d: f64, n_vt: f64, bv: f64, ibv: f64) -> f64 {
    let x = (-(v_d + bv) / n_vt).clamp(-40.0, 40.0);
    ibv / n_vt * fast_exp(x)
}

// Canonical source: melange-devices/src/bjt.rs (BjtEbersMoll, BjtGummelPoon)
// Duplicated here because generated code must be self-contained.

/// Safe exponential using fast_exp (clamp to prevent overflow, matches runtime [-40, 40] range)
#[inline(always)]
fn safe_exp(x: f64) -> f64 {
    fast_exp(x)
}

/// Gummel-Poon base charge factor qb.
///
/// Accounts for Early effect (VAF/VAR) and high-level injection (IKF/IKR).
/// When use_gp=false or all GP params are infinite, returns 1.0 (Ebers-Moll).
///
/// Matches ngspice bjtload.c:571 exactly:
///     q2 = cbe / IKF + cbc / IKR
///     where cbe = IS*(exp(Vbe/(NF*VT)) - 1), cbc = IS*(exp(Vbc/(NR*VT)) - 1)
/// q2 inherits NF/NR emission coefficients via cbe/cbc — it does NOT use bare VT.
#[inline(always)]
fn bjt_qb(
    vbe: f64,
    vbc: f64,
    is: f64,
    vt: f64,
    nf: f64,
    nr: f64,
    sign: f64,
    use_gp: bool,
    vaf: f64,
    var: f64,
    ikf: f64,
    ikr: f64,
) -> f64 {
    if !use_gp {
        return 1.0;
    }
    let vbe_eff = sign * vbe;
    let vbc_eff = sign * vbc;

    // Early effect: q1 = 1 / (1 - Vbe/VAR - Vbc/VAF)
    let q1_denom = 1.0 - vbe_eff / var - vbc_eff / vaf;
    if q1_denom <= 0.0 || q1_denom.abs() < 1e-30 {
        return 1.0;
    }
    let q1 = 1.0 / q1_denom;

    // High-level injection via cbe/cbc with NF*VT / NR*VT and the -1 term
    // (matches ngspice bjtload.c:571).
    let exp_be = safe_exp(vbe_eff / (nf * vt));
    let exp_bc = safe_exp(vbc_eff / (nr * vt));
    let cbe = is * (exp_be - 1.0);
    let cbc = is * (exp_bc - 1.0);
    let q2 = cbe / ikf + cbc / ikr;

    q1 * (1.0 + (1.0 + 4.0 * q2).max(0.0).sqrt()) / 2.0
}

/// BJT collector current Ic(Vbe, Vbc)
/// sign: +1.0 for NPN, -1.0 for PNP (applied to voltages and output current)
/// nf: forward emission coefficient. Transport current uses exp(Vbe/(NF*VT)).
/// nr: reverse emission coefficient. Reverse current uses exp(Vbc/(NR*VT)).
/// When use_gp=true, divides transport current by qb (Gummel-Poon).
#[inline(always)]
fn bjt_ic(
    vbe: f64,
    vbc: f64,
    is: f64,
    vt: f64,
    nf: f64,
    nr: f64,
    beta_r: f64,
    sign: f64,
    use_gp: bool,
    vaf: f64,
    var: f64,
    ikf: f64,
    ikr: f64,
) -> f64 {
    let vbe_eff = sign * vbe;
    let vbc_eff = sign * vbc;
    let nf_vt = nf * vt;
    let nr_vt = nr * vt;
    let exp_be = safe_exp(vbe_eff / nf_vt);
    let exp_bc = safe_exp(vbc_eff / nr_vt);
    let i_cc = is * (exp_be - exp_bc);
    let qb = bjt_qb(vbe, vbc, is, vt, nf, nr, sign, use_gp, vaf, var, ikf, ikr);
    sign * (i_cc / qb - is / beta_r * (exp_bc - 1.0))
}

/// BJT base current Ib(Vbe, Vbc)
/// sign: +1.0 for NPN, -1.0 for PNP
/// nf: forward emission coefficient for ideal base current.
/// nr: reverse emission coefficient for reverse base current.
/// ise, ne: B-E leakage saturation current and emission coefficient.
/// isc, nc: B-C leakage saturation current and emission coefficient.
///
/// Matches ngspice bjtload.c:618:
///     cb = cbe/betaF + cben + cbc/betaR + cbcn
/// The ideal forward base current is NOT divided by qb — that is the collector
/// (transport) current's exclusive modification. GP base-current modulation is
/// limited to what the EM forward / reverse / leakage terms already express.
/// The use_gp / GP-param arguments are retained in the signature for call-site
/// stability but are unused in this function.
#[inline(always)]
#[allow(clippy::too_many_arguments)]
fn bjt_ib(
    vbe: f64,
    vbc: f64,
    is: f64,
    vt: f64,
    nf: f64,
    nr: f64,
    beta_f: f64,
    beta_r: f64,
    sign: f64,
    ise: f64,
    ne: f64,
    isc: f64,
    nc: f64,
    _use_gp: bool,
    _vaf: f64,
    _var: f64,
    _ikf: f64,
    _ikr: f64,
) -> f64 {
    let vbe_eff = sign * vbe;
    let vbc_eff = sign * vbc;
    let nf_vt = nf * vt;
    let nr_vt = nr * vt;
    let exp_be = safe_exp(vbe_eff / nf_vt);
    let exp_bc = safe_exp(vbc_eff / nr_vt);
    // Ideal forward + reverse base current (ngspice: cbe/betaF + cbc/betaR, unmodified by qb)
    let ib_fwd = is / beta_f * (exp_be - 1.0);
    let ib_rev = is / beta_r * (exp_bc - 1.0);
    let mut ib = ib_fwd + ib_rev;
    // B-E leakage current: ISE * (exp(Vbe/(NE*VT)) - 1)
    if ise > 0.0 {
        let ne_vt = ne * vt;
        let exp_be_leak = safe_exp(vbe_eff / ne_vt);
        ib += ise * (exp_be_leak - 1.0);
    }
    // B-C leakage current: ISC * (exp(Vbc/(NC*VT)) - 1)
    if isc > 0.0 {
        let nc_vt = nc * vt;
        let exp_bc_leak = safe_exp(vbc_eff / nc_vt);
        ib += isc * (exp_bc_leak - 1.0);
    }
    sign * ib
}

/// BJT Jacobian: [dIc/dVbe, dIc/dVbc, dIb/dVbe, dIb/dVbc]
/// sign: +1.0 for NPN, -1.0 for PNP (s*s=1, so Jacobian entries are polarity-invariant)
/// nf: forward emission coefficient. nr: reverse emission coefficient.
/// ise, ne: B-E leakage. isc, nc: B-C leakage.
/// When use_gp=true, uses quotient rule for d(Icc/qb)/dV (Gummel-Poon).
#[inline(always)]
fn bjt_jacobian(
    vbe: f64,
    vbc: f64,
    is: f64,
    vt: f64,
    nf: f64,
    nr: f64,
    beta_f: f64,
    beta_r: f64,
    sign: f64,
    use_gp: bool,
    vaf: f64,
    var: f64,
    ikf: f64,
    ikr: f64,
    ise: f64,
    ne: f64,
    isc: f64,
    nc: f64,
) -> [f64; 4] {
    let vbe_eff = sign * vbe;
    let vbc_eff = sign * vbc;
    let nf_vt = nf * vt;
    let nr_vt = nr * vt;
    let exp_be = safe_exp(vbe_eff / nf_vt);
    let exp_bc = safe_exp(vbc_eff / nr_vt);

    // Base current Jacobian (EM components — may be adjusted for GP below)
    let dib_fwd_dvbe = (is / (beta_f * nf_vt)) * exp_be;
    let dib_rev_dvbc = (is / (beta_r * nr_vt)) * exp_bc;
    let mut dib_leak_dvbe = 0.0;
    let mut dib_leak_dvbc = 0.0;
    // ISE leakage contribution to dIb/dVbe
    if ise > 0.0 {
        let ne_vt = ne * vt;
        let exp_be_leak = safe_exp(vbe_eff / ne_vt);
        dib_leak_dvbe = (ise / ne_vt) * exp_be_leak;
    }
    // ISC leakage contribution to dIb/dVbc
    if isc > 0.0 {
        let nc_vt = nc * vt;
        let exp_bc_leak = safe_exp(vbc_eff / nc_vt);
        dib_leak_dvbc = (isc / nc_vt) * exp_bc_leak;
    }

    if !use_gp {
        // Ebers-Moll: simple derivatives
        let dic_dvbe = is / nf_vt * exp_be;
        let dic_dvbc = -(is / nr_vt) * exp_bc - (is / (beta_r * nr_vt)) * exp_bc;
        return [
            dic_dvbe,
            dic_dvbc,
            dib_fwd_dvbe + dib_leak_dvbe,
            dib_rev_dvbc + dib_leak_dvbc,
        ];
    }

    // Gummel-Poon: quotient rule for d(Icc/qb)/dV
    // Icc = is*(exp_be - exp_bc) = cbe - cbc (the -1 terms cancel in the difference)
    let icc = is * (exp_be - exp_bc);
    let dicc_dvbe = is / nf_vt * exp_be;
    let dicc_dvbc = -is / nr_vt * exp_bc;

    // q1 and derivatives
    let q1_denom = 1.0 - vbe_eff / var - vbc_eff / vaf;
    let (q1, dq1_dvbe, dq1_dvbc) = if q1_denom <= 0.0 || q1_denom.abs() < 1e-30 {
        (1.0, 0.0, 0.0)
    } else {
        let q1 = 1.0 / q1_denom;
        (q1, q1 * q1 / var, q1 * q1 / vaf)
    };

    // q2 and derivatives match ngspice bjtload.c:571:
    //     q2 = cbe/IKF + cbc/IKR
    //     cbe = IS*(exp(Vbe/(NF*VT)) - 1), cbc = IS*(exp(Vbc/(NR*VT)) - 1)
    // Reuse exp_be/exp_bc computed above with nf_vt/nr_vt; the -1 constants
    // drop out of the derivatives but matter for q2's value.
    let cbe = is * (exp_be - 1.0);
    let cbc = is * (exp_bc - 1.0);
    let q2 = cbe / ikf + cbc / ikr;
    let dq2_dvbe = (is / (nf_vt * ikf)) * exp_be;
    let dq2_dvbc = (is / (nr_vt * ikr)) * exp_bc;

    // Discriminant D = sqrt(1 + 4*q2)
    let disc = (1.0 + 4.0 * q2).max(0.0);
    let d = disc.sqrt();
    let dd_dvbe = if d > 1e-15 { 2.0 * dq2_dvbe / d } else { 0.0 };
    let dd_dvbc = if d > 1e-15 { 2.0 * dq2_dvbc / d } else { 0.0 };

    // qb = q1 * (1 + D) / 2
    let qb = q1 * (1.0 + d) / 2.0;
    let dqb_dvbe = dq1_dvbe * (1.0 + d) / 2.0 + q1 * dd_dvbe / 2.0;
    let dqb_dvbc = dq1_dvbc * (1.0 + d) / 2.0 + q1 * dd_dvbc / 2.0;

    // Quotient rule: d(Icc/qb)/dV = (dIcc/dV * qb - Icc * dqb/dV) / qb^2
    let qb2 = (qb * qb).max(1e-30);
    let quotient_dvbe = (dicc_dvbe * qb - icc * dqb_dvbe) / qb2;
    let quotient_dvbc = (dicc_dvbc * qb - icc * dqb_dvbc) / qb2;

    let d_bc_term_dvbc = is / (beta_r * nr_vt) * exp_bc;

    // GP base current Jacobian = Ebers-Moll Jacobian (no qb modulation per
    // ngspice bjtload.c:627: gpi = gbe/betaF + gben, gmu = gbc/betaR + gbcn).
    [
        quotient_dvbe,
        quotient_dvbc - d_bc_term_dvbc,
        dib_fwd_dvbe + dib_leak_dvbe,
        dib_rev_dvbc + dib_leak_dvbc,
    ]
}

/// Combined BJT evaluation: returns (Ic, Ib, [dIc/dVbe, dIc/dVbc, dIb/dVbe, dIb/dVbc]).
///
/// Computes exp(Vbe/(NF*VT)) and exp(Vbc/(NR*VT)) once and shares them across current
/// and Jacobian calculations. Reduces from 8-10 exp() to 2-4 per evaluation.
#[inline(always)]
fn bjt_evaluate(
    vbe: f64,
    vbc: f64,
    is: f64,
    vt: f64,
    nf: f64,
    nr: f64,
    beta_f: f64,
    beta_r: f64,
    sign: f64,
    use_gp: bool,
    vaf: f64,
    var: f64,
    ikf: f64,
    ikr: f64,
    ise: f64,
    ne: f64,
    isc: f64,
    nc: f64,
) -> (f64, f64, [f64; 4]) {
    let vbe_eff = sign * vbe;
    let vbc_eff = sign * vbc;
    let nf_vt = nf * vt;
    let nr_vt = nr * vt;

    // Shared exponentials (computed once)
    let exp_be = safe_exp(vbe_eff / nf_vt);
    let exp_bc = safe_exp(vbc_eff / nr_vt);

    // ISE leakage exponential (computed once, only when needed)
    let exp_be_leak = if ise > 0.0 {
        safe_exp(vbe_eff / (ne * vt))
    } else {
        0.0
    };

    // ISC leakage exponential (computed once, only when needed)
    let exp_bc_leak = if isc > 0.0 {
        safe_exp(vbc_eff / (nc * vt))
    } else {
        0.0
    };

    // === Collector current ===
    let i_cc = is * (exp_be - exp_bc);

    // === Base current components ===
    let ib_fwd = is / beta_f * (exp_be - 1.0);
    let ib_rev = is / beta_r * (exp_bc - 1.0);
    let ib_leak_be = if ise > 0.0 {
        ise * (exp_be_leak - 1.0)
    } else {
        0.0
    };
    let ib_leak_bc = if isc > 0.0 {
        isc * (exp_bc_leak - 1.0)
    } else {
        0.0
    };

    // === Base current Jacobian (EM components) ===
    let dib_fwd_dvbe = (is / (beta_f * nf_vt)) * exp_be;
    let dib_rev_dvbc = (is / (beta_r * nr_vt)) * exp_bc;
    let dib_leak_dvbe = if ise > 0.0 {
        (ise / (ne * vt)) * exp_be_leak
    } else {
        0.0
    };
    let dib_leak_dvbc = if isc > 0.0 {
        (isc / (nc * vt)) * exp_bc_leak
    } else {
        0.0
    };

    if !use_gp {
        // Ebers-Moll
        let ic = sign * (i_cc - is / beta_r * (exp_bc - 1.0));
        let ib = sign * (ib_fwd + ib_rev + ib_leak_be + ib_leak_bc);
        let dic_dvbe = is / nf_vt * exp_be;
        let dic_dvbc = -(is / nr_vt) * exp_bc - (is / (beta_r * nr_vt)) * exp_bc;
        return (
            ic,
            ib,
            [
                dic_dvbe,
                dic_dvbc,
                dib_fwd_dvbe + dib_leak_dvbe,
                dib_rev_dvbc + dib_leak_dvbc,
            ],
        );
    }

    // Gummel-Poon — matches ngspice bjtload.c:565-630
    // q1 and derivatives
    let q1_denom = 1.0 - vbe_eff / var - vbc_eff / vaf;
    let (q1, dq1_dvbe, dq1_dvbc) = if q1_denom <= 0.0 || q1_denom.abs() < 1e-30 {
        (1.0, 0.0, 0.0)
    } else {
        let q1 = 1.0 / q1_denom;
        (q1, q1 * q1 / var, q1 * q1 / vaf)
    };

    // q2 = cbe/IKF + cbc/IKR with cbe = is*(exp_be - 1), cbc = is*(exp_bc - 1)
    // where exp_be/exp_bc already use NF*VT / NR*VT (shared with current calc above).
    // Matches ngspice bjtload.c:571.
    let cbe = is * (exp_be - 1.0);
    let cbc = is * (exp_bc - 1.0);
    let q2 = cbe / ikf + cbc / ikr;
    let dq2_dvbe = (is / (nf_vt * ikf)) * exp_be;
    let dq2_dvbc = (is / (nr_vt * ikr)) * exp_bc;

    // Discriminant D = sqrt(1 + 4*q2)
    let disc = (1.0 + 4.0 * q2).max(0.0);
    let d = disc.sqrt();
    let dd_dvbe = if d > 1e-15 { 2.0 * dq2_dvbe / d } else { 0.0 };
    let dd_dvbc = if d > 1e-15 { 2.0 * dq2_dvbc / d } else { 0.0 };

    // qb = q1 * (1 + D) / 2
    let qb = q1 * (1.0 + d) / 2.0;
    let dqb_dvbe = dq1_dvbe * (1.0 + d) / 2.0 + q1 * dd_dvbe / 2.0;
    let dqb_dvbc = dq1_dvbc * (1.0 + d) / 2.0 + q1 * dd_dvbc / 2.0;

    // Ic: transport current modulated by qb (ngspice bjtload.c:617)
    let ic = sign * (i_cc / qb - is / beta_r * (exp_bc - 1.0));
    // Ib: ideal forward + reverse, NOT divided by qb (ngspice bjtload.c:618)
    let ib = sign * (ib_fwd + ib_rev + ib_leak_be + ib_leak_bc);

    // Quotient rule for dIc: d(Icc/qb)/dV = (dIcc/dV * qb - Icc * dqb/dV) / qb^2
    let dicc_dvbe = is / nf_vt * exp_be;
    let dicc_dvbc = -is / nr_vt * exp_bc;
    let qb2 = (qb * qb).max(1e-30);
    let quotient_dvbe = (dicc_dvbe * qb - i_cc * dqb_dvbe) / qb2;
    let quotient_dvbc = (dicc_dvbc * qb - i_cc * dqb_dvbc) / qb2;
    let d_bc_term_dvbc = is / (beta_r * nr_vt) * exp_bc;

    // dIb Jacobian = pure Ebers-Moll (ngspice bjtload.c:627-628: gpi/gmu are
    // not modulated by qb — GP's modulation affects transport current only).
    (
        ic,
        ib,
        [
            quotient_dvbe,
            quotient_dvbc - d_bc_term_dvbc,
            dib_fwd_dvbe + dib_leak_dvbe,
            dib_rev_dvbc + dib_leak_dvbc,
        ],
    )
}

/// BJT with parasitic resistances (RB, RC, RE).
///
/// Given external junction voltages (Vbe_ext, Vbc_ext), solves for internal
/// junction voltages via inner 2D Newton-Raphson, then returns:
///   (Ic, Ib, [dIc/dVbe_ext, dIc/dVbc_ext, dIb/dVbe_ext, dIb/dVbc_ext])
///
/// The inner NR solves: find (Vbe_int, Vbc_int) such that
///   F1 = Vbe_int - Vbe_ext + Ib*RB + (Ic+Ib)*RE = 0
///   F2 = Vbc_int - Vbc_ext + Ib*RB - Ic*RC = 0
/// (note: RE term uses Ie = -(Ic+Ib), so V_E_int = V_E_ext - Ie*RE = V_E_ext + (Ic+Ib)*RE)
///
/// When RB=RC=RE=0, this reduces to direct evaluation (no inner loop).
#[inline(always)]
fn bjt_with_parasitics(
    vbe_ext: f64,
    vbc_ext: f64,
    is: f64,
    vt: f64,
    nf: f64,
    nr: f64,
    beta_f: f64,
    beta_r: f64,
    sign: f64,
    use_gp: bool,
    vaf: f64,
    var: f64,
    ikf: f64,
    ikr: f64,
    ise: f64,
    ne: f64,
    isc: f64,
    nc: f64,
    rb: f64,
    rc: f64,
    re: f64,
) -> (f64, f64, [f64; 4]) {
    const INNER_MAX_ITER: usize = 15;
    const INNER_TOL: f64 = 1e-10;

    // Initial guess: internal = external
    let mut vbe_int = vbe_ext;
    let mut vbc_int = vbc_ext;

    for _iter in 0..INNER_MAX_ITER {
        let (ic, ib, jac_int) = bjt_evaluate(
            vbe_int, vbc_int, is, vt, nf, nr, beta_f, beta_r, sign, use_gp, vaf, var, ikf, ikr,
            ise, ne, isc, nc,
        );
        let dic_dvbe = jac_int[0];
        let dic_dvbc = jac_int[1];
        let dib_dvbe = jac_int[2];
        let dib_dvbc = jac_int[3];

        // Residuals
        let f1 = vbe_int - vbe_ext + ib * rb + (ic + ib) * re;
        let f2 = vbc_int - vbc_ext + ib * rb - ic * rc;

        if f1.abs() < INNER_TOL && f2.abs() < INNER_TOL {
            break;
        }

        // Jacobian of F w.r.t. (Vbe_int, Vbc_int)
        let j11 = 1.0 + dib_dvbe * rb + (dic_dvbe + dib_dvbe) * re;
        let j12 = dib_dvbc * rb + (dic_dvbc + dib_dvbc) * re;
        let j21 = dib_dvbe * rb - dic_dvbe * rc;
        let j22 = 1.0 + dib_dvbc * rb - dic_dvbc * rc;

        // Solve 2x2 via Cramer's rule
        let det = j11 * j22 - j12 * j21;
        if det.abs() < 1e-30 {
            break;
        }
        let inv_det = 1.0 / det;
        let dvbe = (j22 * f1 - j12 * f2) * inv_det;
        let dvbc = (j11 * f2 - j21 * f1) * inv_det;

        // Step limiting: max ±4*VT per iteration
        let max_step = 4.0 * vt;
        let dvbe = dvbe.clamp(-max_step, max_step);
        let dvbc = dvbc.clamp(-max_step, max_step);

        vbe_int -= dvbe;
        vbc_int -= dvbc;
    }

    // Final evaluation at converged internal voltages
    let (ic, ib, jac_int) = bjt_evaluate(
        vbe_int, vbc_int, is, vt, nf, nr, beta_f, beta_r, sign, use_gp, vaf, var, ikf, ikr, ise,
        ne, isc, nc,
    );

    // External Jacobian: J_ext = J_device * J_F^{-1}
    // J_F = [[j11, j12], [j21, j22]] (recompute at converged point)
    let dic_dvbe = jac_int[0];
    let dic_dvbc = jac_int[1];
    let dib_dvbe = jac_int[2];
    let dib_dvbc = jac_int[3];

    let j11 = 1.0 + dib_dvbe * rb + (dic_dvbe + dib_dvbe) * re;
    let j12 = dib_dvbc * rb + (dic_dvbc + dib_dvbc) * re;
    let j21 = dib_dvbe * rb - dic_dvbe * rc;
    let j22 = 1.0 + dib_dvbc * rb - dic_dvbc * rc;

    let det = j11 * j22 - j12 * j21;
    if det.abs() < 1e-30 {
        // Fallback: return intrinsic Jacobian
        return (ic, ib, jac_int);
    }
    let inv_det = 1.0 / det;

    // J_F^{-1} = [[j22, -j12], [-j21, j11]] / det
    let fi11 = j22 * inv_det;
    let fi12 = -j12 * inv_det;
    let fi21 = -j21 * inv_det;
    let fi22 = j11 * inv_det;

    // J_ext = J_device * J_F^{-1}
    let dic_dvbe_ext = dic_dvbe * fi11 + dic_dvbc * fi21;
    let dic_dvbc_ext = dic_dvbe * fi12 + dic_dvbc * fi22;
    let dib_dvbe_ext = dib_dvbe * fi11 + dib_dvbc * fi21;
    let dib_dvbc_ext = dib_dvbe * fi12 + dib_dvbc * fi22;

    (
        ic,
        ib,
        [dic_dvbe_ext, dic_dvbc_ext, dib_dvbe_ext, dib_dvbc_ext],
    )
}

/// Build RHS vector: rhs = rhs_const + A_neg * v_prev + N_i^T * i_nl_prev + input
///
/// The A_neg * v_prev term captures capacitor history contribution
/// via alpha*C*v_prev (implicit in the matrix formulation).
#[inline(always)]
fn build_rhs(input: f64, input_prev: f64, state: &CircuitState) -> [f64; N] {
    let mut rhs = RHS_CONST;

    // A_neg * v_prev contribution (includes alpha*C*v_prev capacitor history)
    rhs[0] += state.a_neg[0][0] * state.v_prev[0] + state.a_neg[0][1] * state.v_prev[1];
    rhs[1] += state.a_neg[1][0] * state.v_prev[0]
        + state.a_neg[1][1] * state.v_prev[1]
        + state.a_neg[1][2] * state.v_prev[2];
    rhs[2] += state.a_neg[2][1] * state.v_prev[1]
        + state.a_neg[2][2] * state.v_prev[2]
        + state.a_neg[2][3] * state.v_prev[3]
        + state.a_neg[2][4] * state.v_prev[4];
    rhs[3] += state.a_neg[3][2] * state.v_prev[2]
        + state.a_neg[3][3] * state.v_prev[3]
        + state.a_neg[3][4] * state.v_prev[4]
        + state.a_neg[3][7] * state.v_prev[7]
        + state.a_neg[3][11] * state.v_prev[11];
    rhs[4] += state.a_neg[4][2] * state.v_prev[2]
        + state.a_neg[4][3] * state.v_prev[3]
        + state.a_neg[4][4] * state.v_prev[4]
        + state.a_neg[4][7] * state.v_prev[7];
    rhs[5] += state.a_neg[5][5] * state.v_prev[5] + state.a_neg[5][6] * state.v_prev[6];
    rhs[6] += state.a_neg[6][5] * state.v_prev[5]
        + state.a_neg[6][6] * state.v_prev[6]
        + state.a_neg[6][10] * state.v_prev[10];
    rhs[7] += state.a_neg[7][3] * state.v_prev[3]
        + state.a_neg[7][4] * state.v_prev[4]
        + state.a_neg[7][7] * state.v_prev[7]
        + state.a_neg[7][10] * state.v_prev[10];
    rhs[8] += state.a_neg[8][8] * state.v_prev[8] + state.a_neg[8][9] * state.v_prev[9];
    rhs[9] += state.a_neg[9][8] * state.v_prev[8] + state.a_neg[9][9] * state.v_prev[9];
    rhs[10] += state.a_neg[10][6] * state.v_prev[6]
        + state.a_neg[10][7] * state.v_prev[7]
        + state.a_neg[10][10] * state.v_prev[10];

    // Add N_i * i_nl_prev contribution
    rhs[2] += N_I[0][2] * state.i_nl_prev[0];
    rhs[2] += N_I[1][2] * state.i_nl_prev[1];
    rhs[4] += N_I[1][4] * state.i_nl_prev[1];
    rhs[4] += N_I[2][4] * state.i_nl_prev[2];
    rhs[5] += N_I[1][5] * state.i_nl_prev[1];
    rhs[7] += N_I[2][7] * state.i_nl_prev[2];
    rhs[8] += N_I[2][8] * state.i_nl_prev[2];

    // Add input contribution (Thevenin: (V_in + V_in_prev) * G_in)
    rhs[INPUT_NODE] += (input + input_prev) / INPUT_RESISTANCE;

    rhs
}

/// Multiply vector by S matrix: result = state.s * rhs
#[inline(always)]
fn mat_vec_mul_s(rhs: &[f64; N], state: &CircuitState) -> [f64; N] {
    let mut result = [0.0f64; N];
    for i in 0..N {
        let mut sum = 0.0;
        for j in 0..N {
            sum += state.s[i][j] * rhs[j];
        }
        result[i] = sum;
    }
    result
}

/// Extract controlling voltages: p = N_v * v_pred
#[inline(always)]
fn extract_controlling_voltages(v_pred: &[f64; N]) -> [f64; M] {
    [-v_pred[2], v_pred[2] - v_pred[5], v_pred[4] - v_pred[8]]
}

/// Solve M×M nonlinear system via Newton-Raphson
///
/// Solves: i_nl - i_d(p + K*i_nl) = 0
/// where p = N_v * v_pred is the linear prediction
#[inline(always)]
fn solve_nonlinear(p: &[f64; M], state: &mut CircuitState) -> [f64; M] {
    const MAX_ITER: usize = 200;
    const TOL: f64 = 1.00000000000000006e-9;
    const SINGULARITY_THRESHOLD: f64 = 1e-15;

    // First-order predictor for NR warm start: i_guess = 2*i_nl[n-1] - i_nl[n-2]
    // Extrapolates the trend from the last two samples. On smooth signals this
    // puts the initial guess much closer to the solution, reducing NR iterations.
    let mut i_nl = [0.0; M];
    for i in 0..M {
        i_nl[i] = 2.0 * state.i_nl_prev[i] - state.i_nl_prev_prev[i];
    }

    // Newton-Raphson iteration
    for iter in 0..MAX_ITER {
        // Compute controlling voltages: v_d = p + K * i_nl
        let v_d0 =
            p[0] + state.k[0][0] * i_nl[0] + state.k[0][1] * i_nl[1] + state.k[0][2] * i_nl[2];
        let v_d1 =
            p[1] + state.k[1][0] * i_nl[0] + state.k[1][1] * i_nl[1] + state.k[1][2] * i_nl[2];
        let v_d2 =
            p[2] + state.k[2][0] * i_nl[0] + state.k[2][1] * i_nl[1] + state.k[2][2] * i_nl[2];

        // Evaluate device currents and Jacobians
        let i_dev0 = diode_current(v_d0, state.device_0_is, state.device_0_n_vt);
        let jdev_0_0 = diode_conductance(v_d0, state.device_0_is, state.device_0_n_vt);
        // BJT 1 forward-active (1D: Vbe→Ic only)
        let vbe_1 = v_d1 * DEVICE_1_SIGN;
        let exp_be_1 = fast_exp(vbe_1 / (DEVICE_1_NF * state.device_1_vt));
        let i_dev1 = state.device_1_is * (exp_be_1 - 1.0) * DEVICE_1_SIGN;
        let jdev_1_1 = state.device_1_is / (DEVICE_1_NF * state.device_1_vt) * exp_be_1;
        // BJT 2 forward-active (1D: Vbe→Ic only)
        let vbe_2 = v_d2 * DEVICE_2_SIGN;
        let exp_be_2 = fast_exp(vbe_2 / (DEVICE_2_NF * state.device_2_vt));
        let i_dev2 = state.device_2_is * (exp_be_2 - 1.0) * DEVICE_2_SIGN;
        let jdev_2_2 = state.device_2_is / (DEVICE_2_NF * state.device_2_vt) * exp_be_2;

        // Residuals: f(i) = i - i_dev(v(i)) = 0
        let f0 = i_nl[0] - i_dev0;
        let f1 = i_nl[1] - i_dev1;
        let f2 = i_nl[2] - i_dev2;

        // Jacobian: J[i][j] = delta_ij - sum_k(jdev_ik * K_eff[k][j])
        let j0_0 = 1.0 - jdev_0_0 * state.k[0][0];
        let j0_1 = 0.0 - jdev_0_0 * state.k[0][1];
        let j0_2 = 0.0 - jdev_0_0 * state.k[0][2];
        let j1_0 = 0.0 - jdev_1_1 * state.k[1][0];
        let j1_1 = 1.0 - jdev_1_1 * state.k[1][1];
        let j1_2 = 0.0 - jdev_1_1 * state.k[1][2];
        let j2_0 = 0.0 - jdev_2_2 * state.k[2][0];
        let j2_1 = 0.0 - jdev_2_2 * state.k[2][1];
        let j2_2 = 1.0 - jdev_2_2 * state.k[2][2];

        // Solve 3x3 system via inline Gaussian elimination
        let mut a = [[j0_0, j0_1, j0_2], [j1_0, j1_1, j1_2], [j2_0, j2_1, j2_2]];
        let mut b = [f0, f1, f2];
        let mut singular = false;
        // Forward elimination with partial pivoting
        for col in 0..3 {
            let mut max_row = col;
            let mut max_val = a[col][col].abs();
            for row in (col + 1)..3 {
                if a[row][col].abs() > max_val {
                    max_val = a[row][col].abs();
                    max_row = row;
                }
            }
            if max_val < SINGULARITY_THRESHOLD {
                singular = true;
                break;
            }
            if max_row != col {
                a.swap(col, max_row);
                b.swap(col, max_row);
            }
            let pivot = a[col][col];
            for row in (col + 1)..3 {
                let factor = a[row][col] / pivot;
                for j in (col + 1)..3 {
                    a[row][j] -= factor * a[col][j];
                }
                b[row] -= factor * b[col];
            }
        }
        if !singular {
            // Back substitution
            for i in (0..3).rev() {
                let mut sum = b[i];
                for j in (i + 1)..3 {
                    sum -= a[i][j] * b[j];
                }
                if a[i][i].abs() < SINGULARITY_THRESHOLD {
                    singular = true;
                    break;
                }
                b[i] = sum / a[i][i];
            }
        }
        if !singular {
            let delta0 = b[0];
            let delta1 = b[1];
            let delta2 = b[2];
            // Voltage-space limiting (SPICE pnjlim/fetlim through K matrix)
            let dv0 = -(state.k[0][0] * delta0 + state.k[0][1] * delta1 + state.k[0][2] * delta2);
            let dv1 = -(state.k[1][0] * delta0 + state.k[1][1] * delta1 + state.k[1][2] * delta2);
            let dv2 = -(state.k[2][0] * delta0 + state.k[2][1] * delta1 + state.k[2][2] * delta2);
            let mut alpha = [1.0_f64; 3];
            let mut any_limited = false;
            if dv0.abs() > 1e-15 {
                let v_lim = pnjlim(v_d0 + dv0, v_d0, state.device_0_n_vt, DEVICE_0_VCRIT);
                let ratio = ((v_lim - v_d0) / dv0).max(0.01);
                if ratio < alpha[0] {
                    alpha[0] = ratio;
                    if ratio < 1.0 {
                        any_limited = true;
                    }
                }
            }
            if dv1.abs() > 1e-15 {
                let v_lim = pnjlim(v_d1 + dv1, v_d1, state.device_1_vt, DEVICE_1_VCRIT);
                let ratio = ((v_lim - v_d1) / dv1).max(0.01);
                if ratio < alpha[1] {
                    alpha[1] = ratio;
                    if ratio < 1.0 {
                        any_limited = true;
                    }
                }
            }
            if dv2.abs() > 1e-15 {
                let v_lim = pnjlim(v_d2 + dv2, v_d2, state.device_2_vt, DEVICE_2_VCRIT);
                let ratio = ((v_lim - v_d2) / dv2).max(0.01);
                if ratio < alpha[2] {
                    alpha[2] = ratio;
                    if ratio < 1.0 {
                        any_limited = true;
                    }
                }
            }
            let alpha_scalar = alpha.iter().copied().fold(1.0_f64, f64::min);
            if alpha_scalar < 1.0 {
                any_limited = true;
            }
            let max_di = delta0.abs().max(delta1.abs()).max(delta2.abs());
            let alpha_scalar = if max_di * alpha_scalar > 0.1 {
                (0.1 / max_di).max(0.01).min(alpha_scalar)
            } else {
                alpha_scalar
            };
            i_nl[0] -= alpha_scalar * delta0;
            i_nl[1] -= alpha_scalar * delta1;
            i_nl[2] -= alpha_scalar * delta2;

            // Convergence: voltage-step (RELTOL, ungated) + current-residual (always)
            {
                let mut nr_converged = true;
                if !any_limited {
                    {
                        let step = dv0 * alpha_scalar;
                        let v_new = v_d0 + step;
                        let v_thr = 1e-3 * v_d0.abs().max(v_new.abs()) + 1e-6;
                        if step.abs() > v_thr {
                            nr_converged = false;
                        }
                    }
                    {
                        let step = dv1 * alpha_scalar;
                        let v_new = v_d1 + step;
                        let v_thr = 1e-3 * v_d1.abs().max(v_new.abs()) + 1e-6;
                        if step.abs() > v_thr {
                            nr_converged = false;
                        }
                    }
                    {
                        let step = dv2 * alpha_scalar;
                        let v_new = v_d2 + step;
                        let v_thr = 1e-3 * v_d2.abs().max(v_new.abs()) + 1e-6;
                        if step.abs() > v_thr {
                            nr_converged = false;
                        }
                    }
                }
                {
                    let i_thr = 1e-3 * i_nl[0].abs().max(i_dev0.abs()).max(1e-9) + 1e-12;
                    if f0.abs() > i_thr {
                        nr_converged = false;
                    }
                }
                {
                    let i_thr = 1e-3 * i_nl[1].abs().max(i_dev1.abs()).max(1e-9) + 1e-12;
                    if f1.abs() > i_thr {
                        nr_converged = false;
                    }
                }
                {
                    let i_thr = 1e-3 * i_nl[2].abs().max(i_dev2.abs()).max(1e-9) + 1e-12;
                    if f2.abs() > i_thr {
                        nr_converged = false;
                    }
                }
                if nr_converged {
                    state.last_nr_iterations = iter as u32;
                    return i_nl;
                }
            }
        } else {
            // Singular Jacobian — damped fallback (0.5 * residual, adaptive clamp)
            {
                let clamp = (i_nl[0].abs() * 0.1).max(0.01);
                i_nl[0] -= (f0 * 0.5).clamp(-clamp, clamp);
            }
            {
                let clamp = (i_nl[1].abs() * 0.1).max(0.01);
                i_nl[1] -= (f1 * 0.5).clamp(-clamp, clamp);
            }
            {
                let clamp = (i_nl[2].abs() * 0.1).max(0.01);
                i_nl[2] -= (f2 * 0.5).clamp(-clamp, clamp);
            }
        }
    }

    // Max iterations reached - return best guess
    state.last_nr_iterations = MAX_ITER as u32;
    // Safety: check for NaN/Inf and fall back to previous values
    if !i_nl[0].is_finite() {
        i_nl[0] = state.i_nl_prev[0];
    }
    if !i_nl[1].is_finite() {
        i_nl[1] = state.i_nl_prev[1];
    }
    if !i_nl[2].is_finite() {
        i_nl[2] = state.i_nl_prev[2];
    }

    i_nl
}

/// Compute final node voltages: v = v_pred + state.s_ni * i_nl
///
/// Uses full i_nl (not delta) for trapezoidal nonlinear integration.
/// Combined with N_i * i_nl_prev in the RHS, this gives the proper
/// trapezoidal average: S * N_i * (i_nl + i_nl_prev).
///
/// The S*N_i product is stored in state.s_ni for sample rate independence.
#[inline(always)]
fn compute_final_voltages(v_pred: &[f64; N], i_nl: &[f64; M], state: &CircuitState) -> [f64; N] {
    let mut v = *v_pred;
    for i in 0..N {
        for j in 0..M {
            v[i] += state.s_ni[i][j] * i_nl[j];
        }
    }
    v
}

/// Update capacitor history for companion model.
///
/// NOTE: In the DK method, capacitor history is implicitly handled by
/// the A_neg * v_prev term in build_rhs. This function is a no-op.
#[inline(always)]
fn update_history(_v: &[f64; N], _state: &mut CircuitState) {
    // Capacitor history is handled implicitly by A_neg * v_prev
}

// =============================================================================
// MAIN PROCESS FUNCTION
// =============================================================================

/// Process a single audio sample through the circuit
///
/// # Arguments
/// * `input` - Input voltage at INPUT_NODE
/// * `state` - Mutable circuit state (preserved across calls)
///
/// # Returns
/// Output voltages at OUTPUT_NODES (one per output channel)
#[inline]
pub fn process_sample(input: f64, state: &mut CircuitState) -> [f64; NUM_OUTPUTS] {
    // Validate input — handle NaN, inf, and extreme values
    let input = if input.is_finite() {
        input.clamp(-100.0, 100.0)
    } else {
        0.0
    };

    // Lazy rebuild: process all pot/switch changes in one batch
    if state.matrices_dirty {
        state.rebuild_matrices();
        state.matrices_dirty = false;
    }

    // Flush denormals in state vectors to prevent 50-100x CPU penalty during silence.
    // (Most DAW hosts set FTZ/DAZ, but generated code should not rely on it.)
    for v in state.v_prev.iter_mut() {
        *v = *v + 1e-25 - 1e-25;
    }
    for v in state.i_nl_prev.iter_mut() {
        *v = *v + 1e-25 - 1e-25;
    }

    // Pre-check: force BE if cooldown active from previous ringing detection.
    let force_be = state.be_cooldown > 0;
    if state.be_cooldown > 0 {
        state.be_cooldown -= 1;
    }

    // Step 1: Build RHS vector from history and input
    let rhs = build_rhs(input, state.input_prev, state);

    // Step 2: Linear prediction: v_pred = S * rhs
    let v_pred = mat_vec_mul_s(&rhs, state);

    // Step 3: Extract controlling voltages for nonlinear devices
    let p = extract_controlling_voltages(&v_pred);

    // Step 4: Solve M×M nonlinear system via Newton-Raphson
    let i_nl = solve_nonlinear(&p, state);

    // Step 5: Compute final node voltages
    let v = compute_final_voltages(&v_pred, &i_nl, state);

    // Step 6: Update history (no-op, handled by A_neg formulation)
    update_history(&v, state);

    // Step 6b: Backward Euler fallback for trapezoidal instability.
    // Triggers when: (a) trapezoidal NR didn't converge, OR (b) any node voltage
    // exceeds supply rails (trapezoidal ringing artifact), OR (c) previous sample
    // used BE (cooldown: stay on BE until ringing decays).
    // BE is L-stable and damps all oscillatory modes that trapezoidal preserves.
    let nr_failed = state.last_nr_iterations >= 200_u32;
    let ringing = v.iter().take(11).any(|&x| x.abs() > 5.50000000000000000e1);
    let need_be = nr_failed || ringing || force_be;
    let (v, i_nl) = if need_be {
        if nr_failed {
            state.diag_nr_max_iter_count += 1;
        }
        // Set cooldown: stay on BE long enough for trapezoidal ringing to decay.
        // 64 samples ≈ 1.5ms at 44.1kHz — enough for most parasitic modes.
        if ringing || nr_failed {
            state.be_cooldown = 64;
        }
        state.diag_be_fallback_count += 1;
        // Rebuild RHS with backward Euler matrices
        let mut rhs_be = [0.0f64; N];
        for i in 0..N {
            let mut sum = RHS_CONST_BE[i];
            for j in 0..N {
                sum += state.a_neg_be[i][j] * state.v_prev[j];
            }
            for j in 0..M {
                sum += N_I[j][i] * state.i_nl_prev[j];
            }
            rhs_be[i] = sum;
        }
        rhs_be[INPUT_NODE] += input / INPUT_RESISTANCE;
        // BE linear prediction: v_pred_be = S_be * rhs_be
        let mut v_pred_be = [0.0f64; N];
        for i in 0..N {
            let mut sum = 0.0;
            for j in 0..N {
                sum += state.s_be[i][j] * rhs_be[j];
            }
            v_pred_be[i] = sum;
        }
        // BE controlling voltages
        let mut p_be = [0.0f64; M];
        for i in 0..M {
            let mut sum = 0.0;
            for j in 0..N {
                sum += N_V[i][j] * v_pred_be[j];
            }
            p_be[i] = sum;
        }
        // BE NR solve: swap k/k_be so solve_nonlinear uses BE kernel
        std::mem::swap(&mut state.k, &mut state.k_be);
        std::mem::swap(&mut state.s_ni, &mut state.s_ni_be);
        let i_nl_be = solve_nonlinear(&p_be, state);
        std::mem::swap(&mut state.k, &mut state.k_be);
        std::mem::swap(&mut state.s_ni, &mut state.s_ni_be);
        // Recover full v from BE
        let mut v_be = v_pred_be;
        for i in 0..N {
            for j in 0..M {
                v_be[i] += state.s_ni_be[i][j] * i_nl_be[j];
            }
        }

        (v_be, i_nl_be)
    } else {
        (v, i_nl)
    };

    // Step 6c: Global node voltage damping safety net.
    // Threshold scales with max DC OP voltage so tube 250V circuits aren't over-damped.
    let (v, i_nl) = {
        let mut max_delta = 0.0_f64;
        for i in 0..11 {
            let d = (v[i] - state.v_prev[i]).abs();
            if d > max_delta {
                max_delta = d;
            }
        }
        // Adaptive threshold: max(2V, 5% of max DC OP node voltage)
        let mut max_dc = 0.0_f64;
        for i in 0..11 {
            let a = state.dc_operating_point[i].abs();
            if a > max_dc {
                max_dc = a;
            }
        }
        let damp_thresh = max_dc.mul_add(0.05, 2.0);
        if max_delta > damp_thresh {
            // This is a last-ditch safety net that should only fire when the
            // solver has produced a pathological step. A nonzero value here is
            // a symptom that needs investigation, not an acceptable steady-state
            // (per CLAUDE.md: "never use output attenuation to mask simulation
            // errors"). Surfaced via state.diag_voltage_damp_count.
            state.diag_voltage_damp_count = state.diag_voltage_damp_count.saturating_add(1);
            let damp = (damp_thresh / max_delta).max(0.01);
            let mut v_d = v;
            for i in 0..N {
                v_d[i] = state.v_prev[i] + damp * (v[i] - state.v_prev[i]);
            }
            let mut i_d = i_nl;
            for i in 0..M {
                i_d[i] = state.i_nl_prev[i] + damp * (i_nl[i] - state.i_nl_prev[i]);
            }
            (v_d, i_d)
        } else {
            (v, i_nl)
        }
    };

    // Step 7: Check for NaN/inf BEFORE updating state (prevents corruption of v_prev/i_nl_prev)
    if !v.iter().all(|x| x.is_finite()) {
        state.v_prev = state.dc_operating_point;
        state.i_nl_prev = DC_NL_I;
        state.i_nl_prev_prev = DC_NL_I;

        state.input_prev = 0.0;
        state.pot_0_resistance = 9.99999999999999854e4;
        state.pot_0_resistance_prev = 9.99999999999999854e4;
        state.be_cooldown = 0;
        state.diag_nan_reset_count += 1;
        // Return DC operating point output instead of zero to avoid discontinuity
        let mut dc_output = [0.0f64; NUM_OUTPUTS];
        for out_idx in 0..NUM_OUTPUTS {
            let raw = state.dc_operating_point[OUTPUT_NODES[out_idx]];
            dc_output[out_idx] = (raw * OUTPUT_SCALES[out_idx]).clamp(-10.0, 10.0);
        }
        return dc_output;
    }

    // Update state for next iteration
    state.v_prev = v;
    state.i_nl_prev_prev = state.i_nl_prev;
    state.i_nl_prev = i_nl;
    state.input_prev = input;

    // (NaN check already done in Step 7, before state update)

    if state.last_nr_iterations >= 200_u32 {
        state.diag_nr_max_iter_count += 1;
    }

    // Step 9: Extract outputs and scale
    let mut output = [0.0f64; NUM_OUTPUTS];
    for out_idx in 0..NUM_OUTPUTS {
        let raw_out = v[OUTPUT_NODES[out_idx]];
        let raw_out = if raw_out.is_finite() { raw_out } else { 0.0 };
        let scaled = raw_out * OUTPUT_SCALES[out_idx];
        let abs_out = scaled.abs();
        if abs_out > state.diag_peak_output {
            state.diag_peak_output = abs_out;
        }
        output[out_idx] = if scaled.is_finite() { scaled } else { 0.0 };
    }
    output
}
